import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Input, Select, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { useAccountingPeriods } from '../../../hooks/useAccountingPeriods';
import { useVoucherInitData } from '../../../hooks/useVoucherInitData';
import { usePxkPermissions } from '../../../hooks/usePxkPermissions';
import { useAppDispatch } from '../../../store/hooks';
import { validateVoucherDateAgainstPeriods } from '../../../utils/accountingPeriodDateValidation';
import { wmsService } from '../../../services/kho/wmsService';
import type { VoucherLineDto } from '../../../services/kho/models';
import { KHO_PATHS } from '../../../appPaths';
import { pxkPageLabels } from '../../../constants/pxkPageLabels';
import { DocumentFormHeader } from '../../../components/layout';
import {
  MaterialLinesGridActions,
  useMaterialLinesSelection,
  VoucherDocumentFormShell,
} from '../../../components/form';
import { LineMaterialSearchCell, MaterialLineTableHeaders } from '../../../components/search';
import df from '../../../styles/documentForm.module.css';

const emptyLine = (): VoucherLineDto => ({
  materialCode: '',
  materialName: '',
  unitCode: '',
  quantity: 1,
  unitPrice: 0,
  amount: 0,
});

const XuatThanhLyPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const { canWrite } = usePxkPermissions();
  const accountingPeriods = useAccountingPeriods();
  const [voucherDate, setVoucherDate] = useState(() => new Date().toISOString().slice(0, 10));
  const [warehouseId, setWarehouseId] = useState('');
  const [description, setDescription] = useState('Xuất thanh lý');
  const [lines, setLines] = useState<VoucherLineDto[]>([emptyLine()]);
  const [saving, setSaving] = useState(false);

  const { copyLine, lineRowProps } = useMaterialLinesSelection(lines, setLines);
  const { warehouseOptions } = useVoucherInitData('create-disposal-issue');
  const whOpts = [{ value: '', label: '— Kho —' }, ...warehouseOptions];

  const updateLine = (idx: number, patch: Partial<VoucherLineDto>) => {
    setLines(prev => prev.map((l, i) => {
      if (i !== idx) return l;
      const next = { ...l, ...patch };
      next.amount = (next.quantity || 0) * (next.unitPrice || 0);
      return next;
    }));
  };

  const addLine = () => setLines(prev => [...prev, emptyLine()]);

  const removeLine = (idx: number) => {
    if (lines.length <= 1) {
      dispatchAppToast(dispatch, { message: pxkPageLabels.minLineWarning, type: 'warning' });
      return;
    }
    setLines(prev => prev.filter((_, i) => i !== idx));
  };

  const handleSave = async () => {
    if (!canWrite) return;
    if (!warehouseId) {
      dispatchAppToast(dispatch, { message: pxkPageLabels.headerWarning, type: 'warning' });
      return;
    }
    if (!lines.some(l => l.materialCode.trim())) {
      dispatchAppToast(dispatch, { message: pxkPageLabels.minLineWarning, type: 'warning' });
      return;
    }
    const periodError = validateVoucherDateAgainstPeriods(voucherDate, accountingPeriods);
    if (periodError) {
      dispatchAppToast(dispatch, { message: periodError, type: 'error' });
      return;
    }
    setSaving(true);
    try {
      await wmsService.createMaterialIssue({
        voucherDate: new Date(voucherDate).toISOString(),
        warehouseId,
        description,
        lines: lines.filter(l => l.materialCode.trim()),
      });
      dispatchAppToast(dispatch, { message: pxkPageLabels.createSuccess, type: 'success' });
      navigate(KHO_PATHS.pxk);
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, pxkPageLabels.saveError),
        type: 'error',
      });
    } finally {
      setSaving(false);
    }
  };

  return (
    <VoucherDocumentFormShell
      testId="erp-kho-xuat-thanh-ly-form"
      header={(
        <DocumentFormHeader
          onBack={() => navigate(KHO_PATHS.pxk)}
          title="Xuất thanh lý"
          isNew
          isReadOnly={!canWrite}
          saving={saving}
          saveLabel="Lưu phiếu xuất"
          onSave={canWrite ? handleSave : undefined}
        />
      )}
    >
      <div className={df.section}>
        <h2 className={df.sectionTitle}>Thông tin chứng từ</h2>
        <div className={df.row4}>
          <div className={df.field}>
            <label className={df.label}>Ngày</label>
            <Input type="date" value={voucherDate} onChange={e => setVoucherDate(e.target.value)} disabled={!canWrite} />
          </div>
          <div className={df.field}>
            <label className={df.label}>Kho</label>
            <Select value={warehouseId} onChange={e => setWarehouseId(e.target.value)} options={whOpts} disabled={!canWrite} />
          </div>
          <div className={`${df.field} ${df.spanCol2}`}>
            <label className={df.label}>Diễn giải</label>
            <Input value={description} onChange={e => setDescription(e.target.value)} disabled={!canWrite} />
          </div>
        </div>
      </div>
      <div className={[df.section, df.linesSection].join(' ')}>
        <h2 className={df.sectionTitle}>Chi tiết vật tư</h2>
        <div className={df.tableWrapper}>
          <table className={[df.linesTable, df.linesTableStacked].join(' ')}>
            <thead>
              <tr>
                <MaterialLineTableHeaders />
                <th>ĐVT</th>
                <th className={df.thAmount}>SL</th>
                <th className={df.thAmount}>Giá</th>
                <th className={df.thDel} />
              </tr>
            </thead>
            <tbody>
              {lines.map((line, idx) => (
                <tr key={idx} {...lineRowProps(idx)}>
                  <LineMaterialSearchCell
                    materialCode={line.materialCode}
                    materialName={line.materialName ?? ''}
                    disabled={!canWrite}
                    onSelect={m => updateLine(idx, {
                      materialCode: m.code,
                      materialName: m.name,
                      unitCode: m.unitCode ?? line.unitCode,
                    })}
                    onClear={() => updateLine(idx, { materialCode: '', materialName: '' })}
                  />
                  <td data-label="ĐVT">
                    <Input value={line.unitCode} onChange={e => updateLine(idx, { unitCode: e.target.value })} disabled={!canWrite} />
                  </td>
                  <td data-label="SL" className={df.tdAmount}>
                    <Input
                      type="number"
                      value={String(line.quantity)}
                      onChange={e => updateLine(idx, { quantity: Number(e.target.value) })}
                      disabled={!canWrite}
                    />
                  </td>
                  <td data-label="Giá" className={df.tdAmount}>
                    <Input
                      type="number"
                      value={String(line.unitPrice)}
                      onChange={e => updateLine(idx, { unitPrice: Number(e.target.value) })}
                      disabled={!canWrite}
                    />
                  </td>
                  <td className={df.tdDel} data-label="">
                    <button
                      type="button"
                      className={df.btnDeleteLine}
                      onClick={() => removeLine(idx)}
                      title="Xóa dòng"
                      disabled={!canWrite}
                    >
                      ×
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <MaterialLinesGridActions
          canEdit={canWrite}
          onAddLine={addLine}
          onCopyLine={copyLine}
          linesCount={lines.length}
        />
      </div>
    </VoucherDocumentFormShell>
  );
};

export default XuatThanhLyPage;
